import{_ as e,o as l,c as a,a2 as n}from"./chunks/framework.DnrXFDHb.js";const o=JSON.parse('{"title":"F03 合約負債與營收能見度分析 — 6290 良維","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6290_良維/20260424/F03_合約負債與營收能見度_財務分析專家.md","filePath":"審計報告庫/財務審計/6290_良維/20260424/F03_合約負債與營收能見度_財務分析專家.md"}'),d={name:"審計報告庫/財務審計/6290_良維/20260424/F03_合約負債與營收能見度_財務分析專家.md"};function r(i,t,s,g,x,y){return l(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="f03-合約負債與營收能見度分析-—-6290-良維" tabindex="-1">F03 合約負債與營收能見度分析 — 6290 良維 <a class="header-anchor" href="#f03-合約負債與營收能見度分析-—-6290-良維" aria-label="Permalink to &quot;F03 合約負債與營收能見度分析 — 6290 良維&quot;">​</a></h1><p><strong>分析日期</strong>：2026-04-24 <strong>資料期間</strong>：2023-2025 (36個月) <strong>資料來源</strong>：FinMind API (資產負債表)、公開財報</p><hr><h2 id="一、核心結論" tabindex="-1">一、核心結論 <a class="header-anchor" href="#一、核心結論" aria-label="Permalink to &quot;一、核心結論&quot;">​</a></h2><p><strong>良維的合約負債規模極小，無法作為營收能見度的有效觀察指標。</strong> 2023-2025年間，合約負債最高僅1,326萬（2023Q3），佔總資產比率從未超過0.17%。這反映良維的商業模式以即時/短期訂單交付為主，而非長約預收款模式。</p><p><strong>營收能見度只能透過客戶訂單動能與月營收趨勢間接判斷</strong>。從2024-2026年月營收連續20個月正成長的趨勢來看，營收能見度實際上不低。</p><hr><h2 id="二、合約負債結構分析" tabindex="-1">二、合約負債結構分析 <a class="header-anchor" href="#二、合約負債結構分析" aria-label="Permalink to &quot;二、合約負債結構分析&quot;">​</a></h2><h3 id="_2-1-歷史合約負債數據" tabindex="-1">2.1 歷史合約負債數據 <a class="header-anchor" href="#_2-1-歷史合約負債數據" aria-label="Permalink to &quot;2.1 歷史合約負債數據&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">季度</th><th style="text-align:center;">合約負債(千元)</th><th style="text-align:center;">佔總資產比</th><th style="text-align:center;">季度變化</th></tr></thead><tbody><tr><td style="text-align:left;">2022Q4</td><td style="text-align:center;">0</td><td style="text-align:center;">0.00%</td><td style="text-align:center;">-</td></tr><tr><td style="text-align:left;">2023Q1</td><td style="text-align:center;">0</td><td style="text-align:center;">0.00%</td><td style="text-align:center;">0</td></tr><tr><td style="text-align:left;">2023Q2</td><td style="text-align:center;">0</td><td style="text-align:center;">0.00%</td><td style="text-align:center;">0</td></tr><tr><td style="text-align:left;">2023Q3</td><td style="text-align:center;">13,260</td><td style="text-align:center;">0.17%</td><td style="text-align:center;">+13,260</td></tr><tr><td style="text-align:left;">2023Q4</td><td style="text-align:center;">7,670</td><td style="text-align:center;">0.09%</td><td style="text-align:center;">-5,590</td></tr><tr><td style="text-align:left;">2024Q1</td><td style="text-align:center;">1,160</td><td style="text-align:center;">0.01%</td><td style="text-align:center;">-6,510</td></tr><tr><td style="text-align:left;">2024Q2</td><td style="text-align:center;">12,570</td><td style="text-align:center;">0.14%</td><td style="text-align:center;">+11,410</td></tr><tr><td style="text-align:left;">2024Q3</td><td style="text-align:center;">9,491</td><td style="text-align:center;">0.11%</td><td style="text-align:center;">-3,079</td></tr><tr><td style="text-align:left;">2024Q4</td><td style="text-align:center;">928</td><td style="text-align:center;">0.01%</td><td style="text-align:center;">-8,563</td></tr><tr><td style="text-align:left;">2025Q1</td><td style="text-align:center;">303</td><td style="text-align:center;">0.00%</td><td style="text-align:center;">-625</td></tr><tr><td style="text-align:left;">2025Q2</td><td style="text-align:center;">38</td><td style="text-align:center;">0.00%</td><td style="text-align:center;">-265</td></tr><tr><td style="text-align:left;">2025Q3</td><td style="text-align:center;">2,286</td><td style="text-align:center;">0.02%</td><td style="text-align:center;">+2,248</td></tr><tr><td style="text-align:left;">2025Q4</td><td style="text-align:center;">1,349</td><td style="text-align:center;">0.01%</td><td style="text-align:center;">-937</td></tr></tbody></table><h3 id="_2-2-合約負債佔營收比重" tabindex="-1">2.2 合約負債佔營收比重 <a class="header-anchor" href="#_2-2-合約負債佔營收比重" aria-label="Permalink to &quot;2.2 合約負債佔營收比重&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">年度</th><th style="text-align:center;">合約負債(年底,千元)</th><th style="text-align:center;">全年營收(百萬)</th><th style="text-align:center;">佔比</th></tr></thead><tbody><tr><td style="text-align:left;">2023</td><td style="text-align:center;">7,670</td><td style="text-align:center;">7,360</td><td style="text-align:center;">0.10%</td></tr><tr><td style="text-align:left;">2024</td><td style="text-align:center;">928</td><td style="text-align:center;">8,040</td><td style="text-align:center;">0.01%</td></tr><tr><td style="text-align:left;">2025</td><td style="text-align:center;">1,349</td><td style="text-align:center;">10,159</td><td style="text-align:center;">0.01%</td></tr></tbody></table><p><strong>佔比極低（0.01-0.10%）</strong>，完全不具備營收預測的參考價值。</p><hr><h2 id="三、商業模式與合約負債關聯性" tabindex="-1">三、商業模式與合約負債關聯性 <a class="header-anchor" href="#三、商業模式與合約負債關聯性" aria-label="Permalink to &quot;三、商業模式與合約負債關聯性&quot;">​</a></h2><h3 id="_3-1-為什麼合約負債如此低" tabindex="-1">3.1 為什麼合約負債如此低？ <a class="header-anchor" href="#_3-1-為什麼合約負債如此低" aria-label="Permalink to &quot;3.1 為什麼合約負債如此低？&quot;">​</a></h3><p>良維的商業模式以**製造代工（OEM/ODM）**為主，主要產品為電源線組、連接器等電子零組件，交易特徵如下：</p><ol><li><strong>短交期訂單模式</strong>：客戶下單後數周至數月內交貨，非長期工程合約</li><li><strong>無大額預收款慣例</strong>：連接器產業慣例以信用交易（30-90天）為主，鮮少預收</li><li><strong>庫存備料模式</strong>：公司依據客戶預測備料，但預測不計入合約負債</li><li><strong>客戶認證週期長，但訂單週期短</strong>：取得認證後，訂單按需求批次下達</li></ol><h3 id="_3-2-產業對比" tabindex="-1">3.2 產業對比 <a class="header-anchor" href="#_3-2-產業對比" aria-label="Permalink to &quot;3.2 產業對比&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">公司類型</th><th style="text-align:center;">合約負債佔比</th><th style="text-align:left;">代表</th></tr></thead><tbody><tr><td style="text-align:left;">消費電子連接器(良維)</td><td style="text-align:center;">&lt;0.5%</td><td style="text-align:left;">6290</td></tr><tr><td style="text-align:left;">系統整合/工程合約</td><td style="text-align:center;">5-20%</td><td style="text-align:left;">中鼎、亞翔等</td></tr><tr><td style="text-align:left;">半導體IP/設計服務</td><td style="text-align:center;">10-30%</td><td style="text-align:left;">創意、智原</td></tr><tr><td style="text-align:left;">SaaS/訂閱制</td><td style="text-align:center;">20-50%</td><td style="text-align:left;">-</td></tr><tr><td style="text-align:left;">太陽能/風電</td><td style="text-align:center;">15-40%</td><td style="text-align:left;">-</td></tr></tbody></table><p>良維屬於合約負債極低的業態，這是商業模式自然所致，非公司經營問題。</p><hr><h2 id="四、替代營收能見度指標" tabindex="-1">四、替代營收能見度指標 <a class="header-anchor" href="#四、替代營收能見度指標" aria-label="Permalink to &quot;四、替代營收能見度指標&quot;">​</a></h2><p>由於合約負債無法作為觀察指標，需從以下面向判斷營收能見度：</p><h3 id="_4-1-月營收趨勢-最直接的能見度指標" tabindex="-1">4.1 月營收趨勢（最直接的能見度指標） <a class="header-anchor" href="#_4-1-月營收趨勢-最直接的能見度指標" aria-label="Permalink to &quot;4.1 月營收趨勢（最直接的能見度指標）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">期間</th><th style="text-align:center;">月營收區間(百萬)</th><th style="text-align:left;">趨勢</th></tr></thead><tbody><tr><td style="text-align:left;">2024H1</td><td style="text-align:center;">435-657</td><td style="text-align:left;">底部穩定</td></tr><tr><td style="text-align:left;">2024H2</td><td style="text-align:center;">663-798</td><td style="text-align:left;">逐步升溫</td></tr><tr><td style="text-align:left;">2025H1</td><td style="text-align:center;">753-880</td><td style="text-align:left;">加速成長</td></tr><tr><td style="text-align:left;">2025H2</td><td style="text-align:center;">788-958</td><td style="text-align:left;">高檔震盪</td></tr><tr><td style="text-align:left;">2026Q1</td><td style="text-align:center;">827-920</td><td style="text-align:left;">維持高檔</td></tr></tbody></table><p><strong>連續20個月YoY正成長</strong>：從2024年4月（營收6.4億）至2025年12月（營收8.5億），每個月營收均高於前一年同期。</p><h3 id="_4-2-營收動能指標" tabindex="-1">4.2 營收動能指標 <a class="header-anchor" href="#_4-2-營收動能指標" aria-label="Permalink to &quot;4.2 營收動能指標&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">指標</th><th style="text-align:center;">2023</th><th style="text-align:center;">2024</th><th style="text-align:center;">2025</th></tr></thead><tbody><tr><td style="text-align:left;">全年營收(百萬)</td><td style="text-align:center;">7,360</td><td style="text-align:center;">8,040</td><td style="text-align:center;">10,159</td></tr><tr><td style="text-align:left;">YoY成長率</td><td style="text-align:center;">-</td><td style="text-align:center;">+9.2%</td><td style="text-align:center;">+26.3%</td></tr><tr><td style="text-align:left;">H2營收/全年</td><td style="text-align:center;">54%</td><td style="text-align:center;">53%</td><td style="text-align:center;">51%</td></tr><tr><td style="text-align:left;">Q4營收動能(百萬)</td><td style="text-align:center;">1,976</td><td style="text-align:center;">2,229</td><td style="text-align:center;">2,674</td></tr></tbody></table><p>H2佔比逐漸趨於50%，反映數據中心需求全年平穩，而非季節性波動。</p><h3 id="_4-3-客戶認證進度-前瞻性指標" tabindex="-1">4.3 客戶認證進度（前瞻性指標） <a class="header-anchor" href="#_4-3-客戶認證進度-前瞻性指標" aria-label="Permalink to &quot;4.3 客戶認證進度（前瞻性指標）&quot;">​</a></h3><p>良維2024-2025年陸續通過：</p><ul><li>多家CSP客戶的新一代伺服器電源連接器認證（2024年底至2025年）</li><li>車用連接器認證（2024年）</li><li>Apple新品供應鏈重新定位</li></ul><p>認證週期通常12-18個月，通過認證後的訂單能見度約6-12個月。<strong>從認證時間軸判斷，2026年營收能見度為正面</strong>。</p><hr><h2 id="五、應收帳款-vs-合約負債的替代意義" tabindex="-1">五、應收帳款 vs 合約負債的替代意義 <a class="header-anchor" href="#五、應收帳款-vs-合約負債的替代意義" aria-label="Permalink to &quot;五、應收帳款 vs 合約負債的替代意義&quot;">​</a></h2><p>由於合約負債極低，應收帳款/營收比率可作為營收確認的替代觀察：</p><table tabindex="0"><thead><tr><th style="text-align:left;">季度</th><th style="text-align:center;">AR/營收比</th><th style="text-align:left;">意義</th></tr></thead><tbody><tr><td style="text-align:left;">2023Q4</td><td style="text-align:center;">26.4%</td><td style="text-align:left;">正常</td></tr><tr><td style="text-align:left;">2024Q1</td><td style="text-align:center;">31.0%</td><td style="text-align:left;">營收成長初期AR提速</td></tr><tr><td style="text-align:left;">2024Q4</td><td style="text-align:center;">29.2%</td><td style="text-align:left;">偏高，營收確認加速</td></tr><tr><td style="text-align:left;">2025Q4</td><td style="text-align:center;">27.3%</td><td style="text-align:left;">改善，收款效率提升</td></tr></tbody></table><p>AR/營收比在2024年略升後，2025年已回落，顯示營收成長同時並未犧牲收款品質。</p><hr><h2 id="六、結論" tabindex="-1">六、結論 <a class="header-anchor" href="#六、結論" aria-label="Permalink to &quot;六、結論&quot;">​</a></h2><h3 id="_6-1-直接判斷" tabindex="-1">6.1 直接判斷 <a class="header-anchor" href="#_6-1-直接判斷" aria-label="Permalink to &quot;6.1 直接判斷&quot;">​</a></h3><ul><li><strong>合約負債非營收能見度的有效指標</strong>：規模極小（&lt;0.2%），不適用</li><li><strong>營收能見度須透過客戶關係與營運動能判斷</strong></li></ul><h3 id="_6-2-間接判斷" tabindex="-1">6.2 間接判斷 <a class="header-anchor" href="#_6-2-間接判斷" aria-label="Permalink to &quot;6.2 間接判斷&quot;">​</a></h3><ul><li><strong>營運動能強勁</strong>：月營收連續20個月年成長，2025年全年營收年增26.3%</li><li><strong>客戶結構轉佳</strong>：從消費電子（季節性強）轉向數據中心（全年平穩），降低波動</li><li><strong>認證時程正面</strong>：2024-2025年新客戶認證結果，支撐2026年營收</li><li><strong>無業績指引參考</strong>：良維未提供正式的營收指引，能見度來自訂單能見度（通常3-6個月）</li></ul><h3 id="_6-3-綜合營收能見度評級-中高" tabindex="-1">6.3 綜合營收能見度評級：<strong>中高</strong> <a class="header-anchor" href="#_6-3-綜合營收能見度評級-中高" aria-label="Permalink to &quot;6.3 綜合營收能見度評級：**中高**&quot;">​</a></h3><p>短期(1-3個月)：很高（月營收趨勢明確） 中期(3-6個月)：中高（客戶訂單能見度） 長期(6-12個月)：中（取決於AI Capex動能延續性）</p><p><strong>能見度來源</strong>：月營收趨勢 &gt; 客戶認證進度 &gt; 法說會展望 &gt; 合約負債（不適用）</p>',48)])])}const c=e(d,[["render",r]]);export{o as __pageData,c as default};
